VALUES
  ('optometrist-moex-03694', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於角膜手術後隱形眼鏡鏡片的驗配，下列敘述何者最錯誤？', '["角膜移植手術後，應等待傷口癒合或縫線調整度數穩定後，再進行隱形眼鏡驗配", "角膜移植手術後，角膜神經敏感度下降，可能導致配戴隱形眼鏡感染風險增加", "雷射近視手術後（post-LASIK），角膜神經敏感度提高，淚水分泌增加、容易產生溢淚模糊", "雷射近視手術後，角膜中央弧度變平，可能導致隱形眼鏡定位變差"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03695', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於無晶體（aphakia）患者的隱形眼鏡驗配，下列方法何者錯誤？', '["為避免弱視產生，嬰幼兒術後無水晶體症隱形眼鏡驗配可在術後3個月開始驗配", "幼兒術後無水晶體症驗配隱形眼鏡，常需選擇較陡基弧", "若三歲以下幼兒術後無晶體，一般可只給予看遠處方隱形眼鏡", "若成人術後無晶體，一般應將看遠與看近分開處方"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03696', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於以角膜塑型鏡片（orthokeratology）矯正近視度數敘述，下列何者錯誤？', '["基弧（base curve）決定於角膜中心弧度以及欲矯正的屈光度", "反轉弧（reverse curve）是鏡片最陡的區域，利用反轉弧與基弧的落差，達到角膜塑型效果", "定位弧（alignment curve），弧度和基弧相同，需與中周邊角膜貼合以保證良好鏡片定位", "周邊弧（peripheral curve），周邊弧最為平坦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03697', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '隱形眼鏡驗配時，下列何者無法以裂隙燈顯微鏡明顯觀察到？', '["淚液膜及瞼板腺（meibomian gland）是否異常", "上下眼瞼結膜是否有濾泡（follicle），乳突（papillae）", "評估鏡片鬆緊度及滑動情形", "檢查鏡片是否造成角膜變形（corneal warpage）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03698', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於螢光染劑的敘述，下列敘述何者錯誤？', '["可用來觀察隱形眼鏡和角膜接觸貼合度", "可用來觀察角膜上皮受損形態", "可用來觀察淚膜的穩定性", "螢光染劑相較於孟加拉紅（rose bengal）角膜染劑毒性強"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03699', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於配戴隱形眼鏡睡覺產生之角膜和鏡片變化，下列敘述何者錯誤？', '["可用氧氣下降", "鏡片溫度上升", "淚液酸度增加", "角膜厚度降低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03700', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列隱形眼鏡造成眼表面變化與表現，何者錯誤？', '["角膜變形（corneal warpage）可發生於軟式或硬式隱形眼鏡的使用，可造成角膜不規則度增加或散光增加", "角膜上皮磨損（corneal abrasion）可發生於隱形眼鏡破損或夾帶異物，常伴有顯著疼痛", "角膜上皮微囊（epithelial microcyst）可發生於隱形眼鏡造成的代謝壓力（metabolic stress），伴有顯著 疼痛", "角膜基質浸潤（stromal infiltrate）可發生於隱形眼鏡造成的角膜感染或新生血管周圍，可影響視力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03701', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '雙眼均為+5.00屈光度遠視患者，原使用框架眼鏡矯正視力，今改用隱形眼鏡完全矯正，下列敘述何者錯誤？', '["隱形眼鏡鏡片度數，會比眼鏡鏡片度數多", "看近時，所使用的調節力（accommodation）減少", "看近時，所使用的內聚力（convergence）變少", "使用隱形眼鏡時，其視網膜上影像大小，會比戴框架眼鏡時成像大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03702', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關軟式隱形眼鏡驗配，若鏡片偏離中心導致角膜未完全覆蓋，下列處置何者較適合？', '["選擇後表面光學區曲率半徑（back optic zone radius, BOZR）較大的鏡片", "選擇後表面光學區曲率半徑較小的鏡片", "選擇含水較高的鏡片", "選擇直徑較大的鏡片"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03703', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '驗配硬式透氧隱形眼鏡時，若鏡片持續偏向某側，下列可能原因及處置何者較不正確？', '["逆散光，可改用後表面散光設計", "鏡片太大，可減少總直徑", "鏡片太平，可改用較陡的鏡片", "角膜頂點異位，可增加總直徑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "60ea5b4a2342", "answer_pdf_sha1": "90acfdb8b3cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
